import{_ as e,o as a,c as i,a3 as o}from"./chunks/framework.LBeL10WQ.js";const g=JSON.parse('{"title":"Social Ads","description":"","frontmatter":{"title":"Social Ads"},"headers":[],"relativePath":"en/advertisers/sponsored-social/index.md","filePath":"en/advertisers/sponsored-social/index.md"}'),r={name:"en/advertisers/sponsored-social/index.md"};function s(n,t,l,d,c,h){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="social-ads-partnership-ads" tabindex="-1">Social Ads (Partnership Ads) <a class="header-anchor" href="#social-ads-partnership-ads" aria-label="Permalink to &quot;Social Ads (Partnership Ads)&quot;">​</a></h1><p>Broadcast your ads via the Instagram, TikTok, and Facebook accounts of our partner e-retailers — leveraging their credibility with their community.</p><div class="info custom-block"><p class="custom-block-title">Format on demand</p><p>This format is available by contacting our team: <a href="mailto:studio@getinside.fr" target="_blank" rel="noreferrer">studio@getinside.fr</a></p></div><hr><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p>Rather than broadcasting a classic ad from your account, you sponsor a post published from the distributor&#39;s account (<strong>Partnership Ads</strong> on Meta, <strong>Spark Ads</strong> on TikTok). The distributor adds the mandatory <em>&quot;Paid partnership&quot;</em> mention.</p><p><strong>The 4-step workflow:</strong></p><ol><li><strong>Brief &amp; Selection</strong> — Choose the partner distributor and transmit the creative angle, visuals, and key messages.</li><li><strong>Creation</strong> — You provide the ready-to-post content, or the distributor / getinside Studio creates it for a native feel.</li><li><strong>Publication</strong> — The distributor publishes with the <em>&quot;Paid partnership&quot;</em> mention and activates the amplification rights.</li><li><strong>Amplification</strong> — getinside activates the Ads campaign on the post to reach a wider audience (followers + Lookalike).</li></ol><hr><h2 id="formats-specifications" tabindex="-1">Formats &amp; Specifications <a class="header-anchor" href="#formats-specifications" aria-label="Permalink to &quot;Formats &amp; Specifications&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Dimensions</th><th style="text-align:left;">Recommendation</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Video</strong> (Reels/TikTok)</td><td style="text-align:left;">9:16 — 1080 × 1920 px, 15–60 s</td><td style="text-align:left;">Recommended — safe zone 15% top/bottom</td></tr><tr><td style="text-align:left;"><strong>Feed Image</strong></td><td style="text-align:left;">4:5 — 1080 × 1350 px</td><td style="text-align:left;">Text ≤ 20% of surface area</td></tr><tr><td style="text-align:left;"><strong>Story</strong></td><td style="text-align:left;">9:16 — 1080 × 1920 px, 15 s/slide</td><td style="text-align:left;">Ensure space for link sticker</td></tr></tbody></table><hr><h2 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Item</th><th style="text-align:left;">Cost</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Platform Fee</strong></td><td style="text-align:left;">12% of invested media budget</td></tr><tr><td style="text-align:left;"><strong>Creative Studio</strong> (optional)</td><td style="text-align:left;">Flat fee 550€ HT per creation</td></tr></tbody></table>',14)])])}const f=e(r,[["render",s]]);export{g as __pageData,f as default};
